/*——————输入框美化——————*/
#send_form {
  /* 容器基础样式 */
  display: flex;
  flex-direction: column;
  width: 93%;/*宽度*/
  max-width: 690px;
  margin: 20px auto;
  padding: 7px;/*▣*/
  border-radius: 15px;/*圆角*/
  background: #f5f5f5; /* 浅灰色背景 */
  position: relative;

  /* 双层描边效果 */
  border: 2px solid #ffffff; /* 白色描边 (外层) */
  box-shadow: 
    0 4px 8px rgba(0, 0, 0, 0.1), /* 右下角灰色阴影 */
    inset 0 0 0 2px #e0e0e0, /* 浅灰色内描边 */
    inset 2px 2px 4px rgba(0, 0, 0, 0.05); /* 内陷阴影 */
}

/* 输入框通用样式 */
#send_form > input[type="text"],
#send_form > .image-url-container > input {
  padding: 12px 16px;
  margin-bottom: 15px;
  border-radius: 12px;
  border: 1px solid #d0d0d0; /* 浅灰色边框 */
  background: #ffffff;
  box-shadow: 
    inset 1px 1px 3px rgba(0, 0, 0, 0.05); /* 内陷阴影 */
  font-size: 14px;
}

/* 图片链接容器-新增3个 */
#send_form > .image-url-container {
  display: flex;
  align-items: center;
  margin-bottom: 10px;
  position: relative;
}

/* 图片链接图标装饰 */
#send_form > .image-url-container::before {
  content: "";
  position: absolute;
  left: 12px;
  pointer-events: none;
}

/* 图片输入框特有样式 */
#send_form > .image-url-container > input {
  padding-left: 35px; /* 给图标留空间 */
  width: 100%;
}

/* 按钮容器 */
#send_form > .button-container {
  display: flex;
  justify-content: flex-end;
  gap: 20px;
}

/* 按钮样式 */
#send_form > .button-container > button {
  padding: 8px 20px;
  border-radius: 15px;
  border: 3px solid #c0c0c0; /* 浅灰色边框 */
  background: linear-gradient(to bottom, #f0f0f0, #e0e0e0); /* 灰白色渐变 */
  color: #333333;
  box-shadow: 
    1px 1px 3px rgba(0, 0, 0, 0.1); /* 右下角阴影 */
}

/* 悬停效果 */
#send_form:hover {
  box-shadow: 
    0 6px 12px rgba(0, 0, 0, 0.15), /* 加深右下阴影 */
    inset 0 0 0 1px #e0e0e0,
    inset 2px 2px 4px rgba(0, 0, 0, 0.05);
}


/*——————复选——————*/
/* 标题下划线渐变 - 改为浅灰色系 */
.title::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 25%;
  width: 50%;
  height: 2px;
  /* 透明-浅灰-透明渐变，适应日间模式 */
  background: linear-gradient(to right, transparent, #D0D0D0, transparent);
}

input[type='checkbox'] {
  appearance: none;
  width: 24px;
  height: 24px;
  /* 黑色主边框 + 白色外描边 */
  border: 2px solid #5C5C5C; /* 核心黑色边框 */
  border-radius: 10px; /* 圆角保持可爱风格 */
  cursor: pointer;
  position: relative;
  /* 纯白背景适应日间模式 */
  background: #FFFFFF; 
  transition: all 0.3s cubic-bezier(0.68, -0.55, 0.27, 1.55);
  /* 多重阴影组合：
     inset 0 2px 4px - 浅灰色内陷阴影（模拟凹陷效果）
     0 0 0 2px - 白色外描边（在黑色边框外）
     2px 2px 9px - 右下角灰色投影（可爱系立体感） */
  box-shadow: 
    inset 0 2px 4px rgba(200, 200, 200, 0.7),
    0 0 0 2px #FFFFFF,
    2px 2px 5px rgba(120, 120, 120, 0.9);
  vertical-align: middle;
}

/* 悬停状态增强立体感 */
input[type='checkbox']:hover {
  transform: scale(1.1); /* 保持可爱弹性效果 */
  /* 强化右下角阴影，减少内阴影深度 */
  box-shadow: 
    inset 0 1px 3px rgba(180, 180, 180, 0.4),
    0 0 0 2px #FFFFFF,
    3px 3px 8px rgba(100, 100, 100, 0.3);
  border-color: #333333; /* 深灰边框增强对比 */
}

/* 选中状态 */
input[type='checkbox']:checked {
  background: #A0A0A0; /* 浅灰色背景 */
  border-color: #5C5C5C; /* 保持黑色边框 */
  animation: jelly 0.6s ease; /* 保留弹性动画 */
  /* 加深内阴影，调整外阴影位置 */
  box-shadow: 
    inset 0 1px 4px rgba(0, 0, 0, 0.2),
    0 0 0 2px #FFFFFF,
    1px 1px 5px rgba(100, 100, 100, 0.3);
}

/* 选中图标（保持原图但调整定位） */
input[type='checkbox']:checked::after {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 120%;
  height: 100%;
  /* 使用原日式图标（深色图标在浅色背景更醒目） */
  background-image: url('https://i.postimg.cc/T35xkc2V/Image-929134514305534.png');
  background-size: 190%;
  background-repeat: no-repeat;
  background-position: center;
  transform: translate(-47%, -42%);
  border-radius: 20px;
}

