.drawer-content select {
  width: 100%;
  padding: px 6px 14px 20px; /* 内边距：顶部缺省/右6px/下14px/左20px */
  appearance: none;
  -webkit-appearance: none;
  -moz-appearance: none;
  cursor: pointer;

  /* 日间白灰色系 */
  background-color: rgba(250, 250, 250, 0.95); /* 主背景：95%透明浅灰白 */
  border: 1px solid #C3C3C3; /* 内层描边*/
  border-radius: 6px; /* 圆角半径：12像素可爱圆角 */

  /* 双层描边+阴影系统 */
  box-shadow: 
    inset 0 0 0 2px #FFFFFF, /* 中间层：2px纯白内描边 */
    inset 4px 2px 3px rgba(240, 240, 240, 0.9), /* 内槽阴影：左上淡白高光 */
    0 0 0 1px rgba(92, 92, 92, 0.4), /* 外层：1px半透灰外描边 */
    3px 3px 5px rgba(150, 150, 150, 0.25); /* 右下角：柔灰色投影 */

  /* 背景图标设置 */
  background-image: url("https://i.postimg.cc/sDdpNrh6/IMG-20250620-044609.png");
  background-repeat: no-repeat;
  background-position: right 0px center;
  background-size: 320px;

  /* 文字样式 */
  font-family: 'Quicksand', sans-serif;
  font-size: 12px;
  color: #5C5C5C; /* 深灰文字(符合#5C5C5C限制) */
  letter-spacing: 0.5px;

  /* 交互动画 */
  transition: all 0.1s cubic-bezier(0.175, 0.25, 0.32, 0.275);
  transform-origin: center;
}

.drawer-content select:hover {
  transform: scale(1.02); /* 悬浮轻微放大 */
  border-color: #A0A0A0; /* 描边变为中灰色 */
  background-color: rgba(255, 255, 255, 0.98); /* 背景变为纯白 */

  /* 更新阴影系统 */
  box-shadow: 
    inset 0 0 0 2px #FFFFFF, /* 保持白色中间层 */
    inset 1px 1px 4px rgba(245, 245, 245, 0.95), /* 强化内高光 */
    0 0 0 1px rgba(160, 160, 160, 0.4), /* 外描边变亮 */
    4px 4px 8px rgba(140, 140, 140, 0.3); /* 加大右下投影 */
}

.drawer-content select:focus {
  outline: none;
  border-color: #8E8E8E; /* 聚焦中灰色描边 */
  background-color: rgba(255, 255, 255, 1); /* 纯白背景 */

  /* 聚焦阴影系统 */
  box-shadow: 
    inset 0 0 0 2px #FFFFFF, /* 保持白色中间层 */
    inset 1px 1px 5px rgba(250, 250, 250, 0.95), /* 强内高光 */
    0 0 0 1px rgba(142, 142, 142, 0.5), /* 强化外描边 */
    0 0 0 3px rgba(200, 200, 200, 0.3), /* 新增聚焦光晕层 */
    5px 5px 10px rgba(130, 130, 130, 0.35); /* 扩散右下投影 */

  animation: jellyFocus 0.9s ease; /* 果冻动画 */
}

.drawer-content select option {
  background: rgba(255, 255, 255, 0.98); /* 选项背景：纯白微透 */
  color: #5C5C5C; /* 深灰文字 */
  padding: 2px 20px;
  margin: 4px 0;
  border-radius: 12px; /* 匹配主元素圆角 */
  transition: all 0.3s ease;
}

.drawer-content select option:hover {
  background: rgba(235, 235, 235, 0.9) !important; /* 悬浮浅灰背景 */
  transform: translateX(8px); /* 右侧位移效果 */
  box-shadow: 2px 2px 6px rgba(180, 180, 180, 0.2); /* 柔和投影 */
}

@keyframes jellyFocus {
  0% { transform: scale(1); }
  10% { transform: scale(1.05); }
  20% { transform: scale(0.98); }
  30% { transform: scale(1); }
}
