/*——————文本编辑框美化——————*/
.reasoning_edit_textarea, .edit_textarea {
    padding: 15px 15px;
    margin: 0;
    width: 100%;
    max-height: 75vh;
    max-height: 75dvh;
    outline: none;

    background: #ffffff; /* 纯白背景 */
    border: 1px solid #5c5c5c; /* 内层深灰描边 */
    outline: 4px solid #ffffff; /* 外层白色描边 */
    border-radius: 8px;
    box-shadow: 
        inset 1px 1px 4px rgba(220,220,220,0.8), /* 左上内陷浅灰阴影 */
        inset -1px -1px 2px rgba(180,180,180,0.8), /* 右下内陷中灰阴影 */
        3px 3px 5px rgba(200,200,200,0.9); /* 右下外部浅灰投影 */

    color: #5c5c5c; /* 深灰色文字 */
    font-size: 16px;
    line-height: 1.6;
    font-family: 'Helvetica Neue', sans-serif;

    transition: border-color 0.3s ease, 
                box-shadow 0.3s ease;

    &:focus {
        box-shadow: 
            inset 1px 1px 3px rgba(230,230,230,0.9), /* 增强内陷高光 */
            inset -1px -1px 3px rgba(170,170,170,0.6), /* 增强内陷阴影 */
            3px 3px 8px rgba(180,180,180,0.4), /* 增强外部投影 */
            0 0 0 2px rgba(220, 220, 220, 0.5); /* 聚焦光晕效果 */
    }

    &::placeholder {
        color: #b0b0b0; /* 中灰色占位符 */
        opacity: 0.8;
    }

    scrollbar-width: thin;
    scrollbar-color: #d0d0d0 #f0f0f0; /* 滚动条灰白色系 */

    &::-webkit-scrollbar {
        width: 1px;
        background: #f0f0f0; /* 浅灰滚动槽 */
    }

    &::-webkit-scrollbar-thumb {
        background: #d0d0d0; /* 中灰滚动条 */
        border-radius: 1px;
    }
}

