/*————弹窗美化————*/
/* 基础容器样式（保持原始结构） */
#toast-container.toast-bottom-center>div,
#toast-container.toast-top-center>div {
  width: 300px;
  margin-left: auto;
  margin-right: auto;
}

/* 全局盒模型设置 */
#toast-container * {
  -moz-box-sizing: border-box;
  -webkit-box-sizing: border-box;
  box-sizing: border-box;
}

/* 标题字体 */
.toast-title {
  font-weight: 700;
}

/* 新增：弹窗基础样式 */
.toast {
  position: relative;
  padding: 15px 20px 15px 65px; /* 左侧留出图片空间 */
  min-height: 60px;
  background: #f8f8f8; /* 主背景色 - 浅灰白 */
  border: 2px solid #d8d8d8; /* 内层描边 - 浅灰 */
  border-radius: 8px; /* 圆角增强可爱感 */
  box-shadow: 
    0 0 0 2px #ffffff, /* 外层描边 - 白色 */
    inset 0 2px 4px rgba(92, 92, 92, 0.08), /* 内陷阴影 - 顶部 */
    inset 0 -1px 1px rgba(92, 92, 92, 0.03), /* 内陷阴影 - 底部 */
    3px 3px 6px rgba(92, 92, 92, 0.1); /* 右下角投影 */
  color: #5c5c5c; /* 最深文本色 */
}

/* 新增：图片容器 */
.toast::before {
  content: "";
  position: absolute;
  left: 6px;
  top: 50%;
  transform: translateY(-50%);
  width: 36px;
  height: 36px;
  background: 
    /* ↓↓↓ 在此替换默认图片链接 ↓↓↓ */
    url("https://i.postimg.cc/g2Xk6WfH/Image-926875252929630.png")
    /* ↑↑↑ 在此替换默认图片链接 ↑↑↑ */
    center/contain no-repeat;
}

/* 新增：成功弹窗图片 */
.toast-success::before {
  background-image: 
    /* ↓↓↓ 在此替换成功图片链接 ↓↓↓ */
    url("https://i.postimg.cc/g2Xk6WfH/Image-926875252929630.png")
    /* ↑↑↑ 在此替换成功图片链接 ↑↑↑ */
    ;
}

/* 新增：错误弹窗图片 */
